cat > trace_loop.cpp << 'EOF'
#include <cstdio>
#include <cstddef>

int main() {
    // Simulate the loop with size = 3
    printf("Loop with size = 3:\n");
    size_t size = 3;
    for (size_t i = size - 1; i >= 0; i--) {
        printf("  i = %zu\n", i);
        if (i == 0) {
            printf("  Breaking manually at i=0 to avoid infinite loop\n");
            break;
        }
    }

    // Simulate the loop with size = 0
    printf("\nLoop with size = 0:\n");
    size = 0;
    size_t i = size - 1;
    printf("  Initial i = size - 1 = %zu\n", i);
    printf("  Is i >= 0? %s\n", (i >= 0) ? "yes" : "no");
    printf("  This would access v[%zu] which is out of bounds!\n", i);

    return 0;
}
EOF
g++ trace_loop.cpp -o trace_loop && ./trace_loop
